  const {
    control,
    formState: {
      errors
    }
  } = useForm<FormModel>({
    mode: 'all',
    defaultValues: {
      documents: [],
      documentsDisabled: [],
      documentsError: []
    }
  });
  const {
    label,
    slotProps
  } = args;
  return <Fields>
      <FieldView>
        <RcSesFileDropzone id='documents' name='documents' control={control} rules={{
        required: true
      }} label={label} errors={errors?.documents as FieldError | undefined} slotProps={slotProps} />
      </FieldView>

      <FieldPreviewRow>
        <PreviewTitle>State previews</PreviewTitle>

        <RcSesFileDropzone id='documentsDisabled' name='documentsDisabled' control={control} rules={{
        required: true
      }} label='Disabled' disabled errors={errors?.documentsDisabled as FieldError | undefined} slotProps={slotProps} />

        <RcSesFileDropzone id='documentsError' name='documentsError' control={control} rules={{
        required: true
      }} label='Error' errors={{
        message: 'Error Message',
        type: 'required'
      }} slotProps={slotProps} />
      </FieldPreviewRow>
    </Fields>;
